// Extract OCR input
const body = $input.first().json.body;
const { imageUrl, documentId, workspaceId } = body;

if (!imageUrl || !documentId) {
  throw new Error('imageUrl and documentId are required');
}

return [{
  json: {
    imageUrl,
    documentId,
    workspaceId
  }
}];

// Extract OCR text from PaddleOCR response
const ocrResult = $input.first().json;
let ocrText = '';

if (ocrResult.texts && Array.isArray(ocrResult.texts)) {
  ocrText = ocrResult.texts.join('\n');
} else if (ocrResult.result && ocrResult.result.texts) {
  ocrText = ocrResult.result.texts.join('\n');
}

// Clean up OCR text
ocrText = ocrText
  .replace(/\s+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return [{
  json: {
    ocrText,
    textLength: ocrText.length,
    documentId: $('Extract Input').item.json.documentId,
    imageUrl: $('Extract Input').item.json.imageUrl
  }
}];

