// Extract vision caption
const visionResult = $input.first().json;
let caption = '';

if (visionResult.choices && visionResult.choices[0]) {
  caption = visionResult.choices[0].message?.content || '';
}

const ocrData = $('Extract OCR Text').item.json;

return [{
  json: {
    ocrText: ocrData.ocrText,
    caption,
    documentId: ocrData.documentId,
    imageUrl: ocrData.imageUrl
  }
}];

// Return success response
const input = $('Extract Input').item.json;
const ocrData = $('Extract OCR Text').item.json;

return [{
  json: {
    success: true,
    documentId: input.documentId,
    ocrTextLength: ocrData.textLength,
    hasCaption: true
  }
}];
